import React from 'react';
import { MDXRenderer } from 'gatsby-plugin-mdx';
import { graphql } from 'gatsby';
import Layout from '../components/layout';

const MdxPageTemplate = ({ data }) => {
  const { mdx } = data;

  return (
    <Layout>
      <article className="prose mx-auto px-6 py-8">
        <h1 className="text-3xl font-bold mb-4">{mdx.frontmatter.title}</h1>
        <p className="text-gray-600 mb-6">{mdx.frontmatter.date}</p>
        {/* <MDXRenderer>{mdx.body}</MDXRenderer> */}
      </article>
    </Layout>
  );
};

export const query = graphql`
  query($id: String!) {
    mdx(id: { eq: $id }) {
      frontmatter {
        title
        date(formatString: "MMMM DD, YYYY")
      }
      body
    }
  }
`;

export default MdxPageTemplate;